// Destructure both candidate results so r1 / r2 are visible to z3 by name.
let (sp1, ack1) = r1;
let (sp2, ack2) = r2;

// `abstractify_seq_of_cpackets_to_set_of_sht_packets` is an `open` spec fn
// defined as `cps.map_values(|cp: CPacket| cp@).to_set()`. Asserting the
// definitional unfolding via Set-extensionality (`=~=`) for both runs forces
// the same `map_values(...).to_set()` shape into z3's context on both sides,
// so the `out` argument that `receive_packet` quantifies over has a matching
// triggerable form across the two ensures-conjuncts.
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@)
       =~= sp1@.map_values(|cp: CPacket| cp@).to_set());
assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@)
       =~= sp2@.map_values(|cp: CPacket| cp@).to_set());

// `outbound_packet_seq_is_valid` is `open`; the LHS literally _is_ the RHS
// forall by definitional unfolding. Re-asserting in iff-form pins the trigger
// `outbound_packet_is_valid(&sp_i@[i])` into the local fact set for both runs,
// so z3 can instantiate both per-run foralls at the same index i.
assert(outbound_packet_seq_is_valid(sp1@) <==>
       (forall |i: int| 0 <= i < sp1@.len() ==> #[trigger] outbound_packet_is_valid(&sp1@[i])));
assert(outbound_packet_seq_is_valid(sp2@) <==>
       (forall |i: int| 0 <= i < sp2@.len() ==> #[trigger] outbound_packet_is_valid(&sp2@[i])));

// Same trigger-alignment trick for the `outbound_packet_seq_has_correct_srcs`
// forall that lives inside `host_state_common_postconditions`: bring both
// per-run quantifiers into scope with a shared `pre_self_.constants.me@`
// witness so z3 can line them up.
assert(outbound_packet_seq_has_correct_srcs(sp1@, pre_self_.constants.me@) <==>
       (forall |i: int| 0 <= i < sp1@.len() ==> #[trigger] sp1@[i].src@ == pre_self_.constants.me@));
assert(outbound_packet_seq_has_correct_srcs(sp2@, pre_self_.constants.me@) <==>
       (forall |i: int| 0 <= i < sp2@.len() ==> #[trigger] sp2@[i].src@ == pre_self_.constants.me@));
